prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?normalizedId ?originalId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" ;
       tai:belongsTo ?corpus .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created ;
         tai:normalizedId ?normalizedId ;
         tai:originalId ?originalId .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  ?choreo tai:belongsTo ?model .

  FILTER(CONTAINS(LCASE(STR(?taskName)), "offer") || 
          CONTAINS(LCASE(STR(?taskName)), "making offer") ||
          CONTAINS(LCASE(STR(?taskName)), "make an offer") ||
          CONTAINS(LCASE(STR(?taskName)), "makingoff"))
}
ORDER BY DESC(?created)
LIMIT 25

