prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?type ?elemName (COUNT(*) AS ?cnt) WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" ;
       tai:belongsTo ?corpus .
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .

  ?elem a ?type ;
        tai:belongsTo ?choreo ;
        bbo:name ?elemName .
  FILTER(STRLEN(STR(?elemName)) > 0)
}
GROUP BY ?type ?elemName
ORDER BY DESC(?cnt)
LIMIT 25

